#pragma once

// Define the CSR address of xdma, should be generated by scala
#include "snax_xdma_addr.h"
// #define XDMA_DEBUG
#ifdef XDMA_DEBUG
#define XDMA_DEBUG_PRINT(...) printf(__VA_ARGS__)
#else
#define XDMA_DEBUG_PRINT(...)
#endif

// Define the base address of XDMA MMIO
#define SNAX_XDMA_CFG_ADDR 960
__attribute__((always_inline)) static inline uint32_t snax_read_xdma_cfg_reg(uint32_t addr) {
    return csrr_ss(SNAX_XDMA_CFG_ADDR + addr);
}

__attribute__((always_inline)) static inline void snax_write_xdma_cfg_reg(uint32_t addr, uint32_t value) {
    csrw_ss(SNAX_XDMA_CFG_ADDR + addr, value);
}

// Is `addr` inside the calling cluster's local L1 (TCDM)? The xDMA engine is
// cluster-local: it only has a port into local L1, so a plain transfer needs at
// least one endpoint here. Uses the low-32 bits (cross-chiplet high-32
// addressing is out of scope). snrt_l1_start_addr / snrt_l1_end_addr
// (occamy_memory.h) are visible here via snrt.h's include order.
static inline bool xdma_addr_in_local_l1(uint64_t addr) {
    uint32_t lo = (uint32_t)addr;
    return (lo >= snrt_l1_start_addr()) && (lo < snrt_l1_end_addr());
}

// Data Copy Task
__attribute__((always_inline)) inline int32_t xdma_memcpy_nd_full_addr(
    uint64_t src, uint64_t dst, uint32_t spatial_stride_src,
    uint32_t spatial_stride_dst, uint32_t temp_dim_src,
    uint32_t* temp_stride_src, uint32_t* temp_bound_src, uint32_t temp_dim_dst,
    uint32_t* temp_stride_dst, uint32_t* temp_bound_dst,
    uint32_t enabled_chan_src, uint32_t enabled_chan_dst,
    uint32_t enabled_byte_dst) {
    // xDMA is cluster-local: it only has a port into the calling cluster's L1,
    // so at least one endpoint must live there. Enforced here so every memcpy
    // path (xdma_memcpy_1d_full_addr / _nd / _1d all delegate to this) is
    // covered without each caller repeating the check. Returns the error code
    // only; the caller-side wrapper (BINGO_XDMA_TRY) reports it.
    if (!xdma_addr_in_local_l1(src) && !xdma_addr_in_local_l1(dst)) {
        return -2;  // no transfer endpoint in local L1
    }
    snax_write_xdma_cfg_reg(XDMA_SRC_ADDR_PTR_LSB, (uint32_t)src);
    snax_write_xdma_cfg_reg(XDMA_SRC_ADDR_PTR_MSB, (uint32_t)(src >> 32));

    snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_LSB, (uint32_t)dst);
    snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_MSB, (uint32_t)(dst >> 32));

#pragma GCC unroll 16
    for (uint32_t i = 1; i < XDMA_MAX_DST_COUNT; i++) {
        snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_LSB + i * 2, 0);
        snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_MSB + i * 2, 0);
    }

    // Rule check
    // The enabled spatial bound for input should be equal to the enabled
    // Src frame count and dst frame count should be equal
    uint32_t src_size = 1;
    if (temp_dim_src > 0) {
        for (uint32_t i = 0; i < temp_dim_src; i++) {
            src_size *= temp_bound_src[i];
        }
    }
    uint32_t dst_size = 1;
    if (temp_dim_dst > 0) {
        for (uint32_t i = 0; i < temp_dim_dst; i++) {
            dst_size *= temp_bound_dst[i];
        }
    }
    if (src_size != dst_size) {
        XDMA_DEBUG_PRINT("src loop and dst loop is not equal\n");
        // return -3;
    }
    // Spatial Stride at src
    snax_write_xdma_cfg_reg(XDMA_SRC_SPATIAL_STRIDE_PTR, spatial_stride_src);

    // Spatial Stride at dst
    snax_write_xdma_cfg_reg(XDMA_DST_SPATIAL_STRIDE_PTR, spatial_stride_dst);

    // Temporal Dimension 0 to n at src
    for (uint32_t i = 0; i < temp_dim_src; i++) {
        if (i >= XDMA_SRC_TEMP_DIM) {
            XDMA_DEBUG_PRINT("Source dimension is too high for xdma\n");
            return -4;
        }
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_BOUND_PTR + i, temp_bound_src[i]);
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_STRIDE_PTR + i,
                                temp_stride_src[i]);
    }
    // Dimension n to MAX at src
    for (uint32_t i = temp_dim_src; i < XDMA_SRC_TEMP_DIM; i++) {
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_BOUND_PTR + i, 1);
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_STRIDE_PTR + i, 0);
    }
    // Temporal Dimension 0 to n at dst
    for (uint32_t i = 0; i < temp_dim_dst; i++) {
        if (i >= XDMA_DST_TEMP_DIM) {
            XDMA_DEBUG_PRINT("Destination dimension is too high for xdma\n");
            return -4;
        }
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_BOUND_PTR + i, temp_bound_dst[i]);
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_STRIDE_PTR + i,
                                temp_stride_dst[i]);
    }
    // Dimension n to MAX at dst
#pragma GCC unroll 5
    for (uint32_t i = temp_dim_dst; i < XDMA_DST_TEMP_DIM; i++) {
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_BOUND_PTR + i, 1);
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_STRIDE_PTR + i, 0);
    }
    // Enabled channel at src
    snax_write_xdma_cfg_reg(XDMA_SRC_ENABLED_CHAN_PTR, enabled_chan_src);
    // Enabled channel at dst
    snax_write_xdma_cfg_reg(XDMA_DST_ENABLED_CHAN_PTR, enabled_chan_dst);
    // Enabled byte at dst
    snax_write_xdma_cfg_reg(XDMA_DST_ENABLED_BYTE_PTR, enabled_byte_dst);
    return 0;
}

inline int32_t xdma_memcpy_nd(void* src, void* dst, uint32_t spatial_stride_src,
                              uint32_t spatial_stride_dst,
                              uint32_t temp_dim_src, uint32_t* temp_stride_src,
                              uint32_t* temp_bound_src, uint32_t temp_dim_dst,
                              uint32_t* temp_stride_dst,
                              uint32_t* temp_bound_dst,
                              uint32_t enabled_chan_src,
                              uint32_t enabled_chan_dst,
                              uint32_t enabled_byte_dst) {
    uint64_t cluster_base_address_h = snrt_cluster_base_addrh();
    cluster_base_address_h = cluster_base_address_h << 32;
    return xdma_memcpy_nd_full_addr(
        (uint64_t)src + cluster_base_address_h,
        (uint64_t)dst + cluster_base_address_h, spatial_stride_src,
        spatial_stride_dst, temp_dim_src, temp_stride_src, temp_bound_src,
        temp_dim_dst, temp_stride_dst, temp_bound_dst, enabled_chan_src,
        enabled_chan_dst, enabled_byte_dst);
}

inline int32_t xdma_memcpy_1d_full_addr(uint64_t src, uint64_t dst,
                                        uint32_t size) {
    if (size % XDMA_WIDTH != 0) {
        XDMA_DEBUG_PRINT("Size is not multiple of XDMA_WIDTH\n");
        return -1;
    }
    uint32_t temporal_stride[1] = {XDMA_WIDTH};
    uint32_t temporal_bound[1] = {size / XDMA_WIDTH};
    return xdma_memcpy_nd_full_addr(
        src, dst, XDMA_WIDTH / XDMA_SPATIAL_CHAN,
        XDMA_WIDTH / XDMA_SPATIAL_CHAN, 1, temporal_stride, temporal_bound, 1,
        temporal_stride, temporal_bound, 0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF);
}

inline int32_t xdma_memcpy_1d(void* src, void* dst, uint32_t size) {
    if (size % XDMA_WIDTH != 0) {
        XDMA_DEBUG_PRINT("Size is not multiple of XDMA_WIDTH\n");
        return -1;
    }
    uint32_t temporal_stride[1] = {XDMA_WIDTH};
    uint32_t temporal_bound[1] = {size / XDMA_WIDTH};
    return xdma_memcpy_nd(src, dst, XDMA_WIDTH / XDMA_SPATIAL_CHAN,
                          XDMA_WIDTH / XDMA_SPATIAL_CHAN, 1, temporal_stride,
                          temporal_bound, 1, temporal_stride, temporal_bound,
                          0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF);
}

// Multicast Task
inline int32_t xdma_multicast_nd_full_address(
    uint64_t src, uint64_t* dst, uint32_t dst_num, uint32_t spatial_stride_src,
    uint32_t spatial_stride_dst, uint32_t temp_dim_src,
    uint32_t* temp_stride_src, uint32_t* temp_bound_src, uint32_t temp_dim_dst,
    uint32_t* temp_stride_dst, uint32_t* temp_bound_dst,
    uint32_t enabled_chan_src, uint32_t enabled_chan_dst,
    uint32_t enabled_byte_dst) {
    snax_write_xdma_cfg_reg(XDMA_SRC_ADDR_PTR_LSB, (uint32_t)src);
    snax_write_xdma_cfg_reg(XDMA_SRC_ADDR_PTR_MSB, (uint32_t)(src >> 32));

    if (dst_num > XDMA_MAX_DST_COUNT) {
        XDMA_DEBUG_PRINT("Number of destination exceeds the hardware limit\n");
    }

    // Set the destination address for each destination
    for (uint32_t i = 0; i < dst_num; i++) {
        snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_LSB + i * 2,
                                (uint32_t)dst[i]);
        snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_MSB + i * 2,
                                (uint32_t)(dst[i] >> 32));
    }

    // The remaining is set to 0, and XDMA will stop the chained copy to the
    // next destination
    for (uint32_t i = dst_num; i < XDMA_MAX_DST_COUNT; i++) {
        snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_LSB + i * 2, 0);
        snax_write_xdma_cfg_reg(XDMA_DST_ADDR_PTR_MSB + i * 2, 0);
    }
    // Rule check
    // The enabled spatial bound for input should be equal to the enabled
    // Src frame count and dst frame count should be equal
    uint32_t src_size = 1;
    if (temp_dim_src > 0) {
        for (uint32_t i = 0; i < temp_dim_src; i++) {
            src_size *= temp_bound_src[i];
        }
    }
    uint32_t dst_size = 1;
    if (temp_dim_dst > 0) {
        for (uint32_t i = 0; i < temp_dim_dst; i++) {
            dst_size *= temp_bound_dst[i];
        }
    }
    if (src_size != dst_size) {
        XDMA_DEBUG_PRINT("src loop and dst loop is not equal\n");
        // return -3;
    }

    // Spatial Stride at src
    snax_write_xdma_cfg_reg(XDMA_SRC_SPATIAL_STRIDE_PTR, spatial_stride_src);

    // Spatial Stride at dst
    snax_write_xdma_cfg_reg(XDMA_DST_SPATIAL_STRIDE_PTR, spatial_stride_dst);

    // Temporal Dimension 0 to n at src
    for (uint32_t i = 0; i < temp_dim_src; i++) {
        if (i >= XDMA_SRC_TEMP_DIM) {
            XDMA_DEBUG_PRINT("Source dimension is too high for xdma\n");
            return -4;
        }
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_BOUND_PTR + i, temp_bound_src[i]);
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_STRIDE_PTR + i,
                                temp_stride_src[i]);
    }
    // Dimension n to MAX at src
    for (uint32_t i = temp_dim_src; i < XDMA_SRC_TEMP_DIM; i++) {
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_BOUND_PTR + i, 1);
        snax_write_xdma_cfg_reg(XDMA_SRC_TEMP_STRIDE_PTR + i, 0);
    }
    // Temporal Dimension 0 to n at dst
    for (uint32_t i = 0; i < temp_dim_dst; i++) {
        if (i >= XDMA_DST_TEMP_DIM) {
            XDMA_DEBUG_PRINT("Destination dimension is too high for xdma\n");
            return -4;
        }
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_BOUND_PTR + i, temp_bound_dst[i]);
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_STRIDE_PTR + i,
                                temp_stride_dst[i]);
    }
    // Dimension n to MAX at dst
#pragma GCC unroll 5
    for (uint32_t i = temp_dim_dst; i < XDMA_DST_TEMP_DIM; i++) {
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_BOUND_PTR + i, 1);
        snax_write_xdma_cfg_reg(XDMA_DST_TEMP_STRIDE_PTR + i, 0);
    }
    // Enabled channel at src
    snax_write_xdma_cfg_reg(XDMA_SRC_ENABLED_CHAN_PTR, enabled_chan_src);
    // Enabled channel at dst
    snax_write_xdma_cfg_reg(XDMA_DST_ENABLED_CHAN_PTR, enabled_chan_dst);
    // Enabled byte at dst
    snax_write_xdma_cfg_reg(XDMA_DST_ENABLED_BYTE_PTR, enabled_byte_dst);
    return 0;
}

inline int32_t xdma_multicast_nd(
    void* src, void** dst, uint32_t dst_num, uint32_t spatial_stride_src,
    uint32_t spatial_stride_dst, uint32_t temp_dim_src,
    uint32_t* temp_stride_src, uint32_t* temp_bound_src, uint32_t temp_dim_dst,
    uint32_t* temp_stride_dst, uint32_t* temp_bound_dst,
    uint32_t enabled_chan_src, uint32_t enabled_chan_dst,
    uint32_t enabled_byte_dst) {
    uint64_t cluster_base_address_h = snrt_cluster_base_addrh();
    cluster_base_address_h = cluster_base_address_h << 32;

    uint64_t dst_full_address[XDMA_MAX_DST_COUNT];
    for (uint32_t i = 0; i < dst_num; i++) {
        dst_full_address[i] = (uint64_t)dst[i] + cluster_base_address_h;
    }
    for (uint32_t i = dst_num; i < XDMA_MAX_DST_COUNT; i++) {
        dst_full_address[i] = 0;
    }

    return xdma_multicast_nd_full_address(
        (uint64_t)src + cluster_base_address_h, dst_full_address, dst_num,
        spatial_stride_src, spatial_stride_dst, temp_dim_src, temp_stride_src,
        temp_bound_src, temp_dim_dst, temp_stride_dst, temp_bound_dst,
        enabled_chan_src, enabled_chan_dst, enabled_byte_dst);
}

inline int32_t xdma_multicast_1d_full_address(uint64_t src, uint64_t* dst,
                                              uint32_t dst_num, uint32_t size) {
    if (size % XDMA_WIDTH != 0) {
        printf_safe("Size is not multiple of XDMA_WIDTH\n");
        return -1;
    }
    uint32_t temporal_stride[1] = {XDMA_WIDTH};
    uint32_t temporal_bound[1] = {size / XDMA_WIDTH};
    return xdma_multicast_nd_full_address(
        src, dst, dst_num, XDMA_WIDTH / XDMA_SPATIAL_CHAN,
        XDMA_WIDTH / XDMA_SPATIAL_CHAN, 1, temporal_stride, temporal_bound, 1,
        temporal_stride, temporal_bound, 0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF);
}

inline int32_t xdma_multicast_1d(void* src, void** dst, uint32_t dst_num,
                                 uint32_t size) {
    if (size % XDMA_WIDTH != 0) {
        printf_safe("Size is not multiple of XDMA_WIDTH\n");
        return -1;
    }
    uint32_t temporal_stride[1] = {XDMA_WIDTH};
    uint32_t temporal_bound[1] = {size / XDMA_WIDTH};
    return xdma_multicast_nd(src, dst, dst_num, XDMA_WIDTH / XDMA_SPATIAL_CHAN,
                             XDMA_WIDTH / XDMA_SPATIAL_CHAN, 1, temporal_stride,
                             temporal_bound, 1, temporal_stride, temporal_bound,
                             0xFFFFFFFF, 0xFFFFFFFF, 0xFFFFFFFF);
}

// Extension
// xdma extension interface
inline int32_t xdma_enable_src_ext(uint8_t ext, uint32_t* csr_value) {
    if (ext >= XDMA_SRC_EXT_NUM) {
        return -1;
    }
    uint8_t custom_csr_list[XDMA_SRC_EXT_NUM] = XDMA_SRC_EXT_CUSTOM_CSR_NUM;
    uint32_t csr_offset = XDMA_SRC_EXT_CSR_PTR;
    for (uint8_t i = 0; i < ext; i++) {
        csr_offset += custom_csr_list[i];
    }

    snax_write_xdma_cfg_reg(
        XDMA_SRC_ENABLE_PTR,
        snax_read_xdma_cfg_reg(XDMA_SRC_ENABLE_PTR) | (1 << ext));

    for (uint8_t i = 0; i < custom_csr_list[ext]; i++) {
        snax_write_xdma_cfg_reg(csr_offset + i, csr_value[i]);
    }
    return 0;
}

inline int32_t xdma_enable_dst_ext(uint8_t ext, uint32_t* csr_value) {
    if (ext >= XDMA_DST_EXT_NUM) {
        return -1;
    }
    uint8_t custom_csr_list[XDMA_DST_EXT_NUM] = XDMA_DST_EXT_CUSTOM_CSR_NUM;
    uint32_t csr_offset = XDMA_DST_EXT_CSR_PTR;
    for (uint8_t i = 0; i < ext; i++) {
        csr_offset += custom_csr_list[i];
    }

    snax_write_xdma_cfg_reg(
        XDMA_DST_ENABLE_PTR,
        snax_read_xdma_cfg_reg(XDMA_DST_ENABLE_PTR) | (1 << ext));
    for (uint8_t i = 0; i < custom_csr_list[ext]; i++) {
        snax_write_xdma_cfg_reg(csr_offset + i, csr_value[i]);
    }
    return 0;
}

__attribute__((always_inline)) inline int32_t xdma_disable_src_ext(uint8_t ext) {
    if (ext >= XDMA_SRC_EXT_NUM) {
        return 0;
    }
    snax_write_xdma_cfg_reg(
        XDMA_SRC_ENABLE_PTR,
        snax_read_xdma_cfg_reg(XDMA_SRC_ENABLE_PTR) & ~(1 << ext));
    return 0;
}

__attribute__((always_inline)) inline int32_t xdma_disable_dst_ext(uint8_t ext) {
    if (ext >= XDMA_DST_EXT_NUM) {
        return 0;
    }
    snax_write_xdma_cfg_reg(
        XDMA_DST_ENABLE_PTR,
        snax_read_xdma_cfg_reg(XDMA_DST_ENABLE_PTR) & ~(1 << ext));
    return 0;
}

// Start
inline uint32_t xdma_start() {
    int local_task_id = snax_read_xdma_cfg_reg(XDMA_COMMIT_LOCAL_TASK_PTR);
    int remote_task_id = snax_read_xdma_cfg_reg(XDMA_COMMIT_REMOTE_TASK_PTR);
    snax_write_xdma_cfg_reg(XDMA_START_PTR, 1);
    while (1) {
        // Wait for xdma to start
        if (snax_read_xdma_cfg_reg(XDMA_COMMIT_LOCAL_TASK_PTR) !=
            local_task_id) {
            return snax_read_xdma_cfg_reg(XDMA_COMMIT_LOCAL_TASK_PTR);
        }
        if (snax_read_xdma_cfg_reg(XDMA_COMMIT_REMOTE_TASK_PTR) !=
            remote_task_id) {
            return snax_read_xdma_cfg_reg(XDMA_COMMIT_REMOTE_TASK_PTR);
        }
    }
}

// Wait xdma to finished
inline void xdma_local_wait(uint32_t task_id) {
    while (snax_read_xdma_cfg_reg(XDMA_FINISH_LOCAL_TASK_PTR) < task_id) {
        // Wait for xdma to finish
    }
}

inline void xdma_remote_wait(uint32_t task_id) {
    while (snax_read_xdma_cfg_reg(XDMA_FINISH_REMOTE_TASK_PTR) < task_id) {
        // Wait for xdma to finish
    }
}

// Wait for xdma task completion, automatically choosing local or remote
// based on whether src and dst are in the same cluster's TCDM.
inline void xdma_wait_task(uint64_t src_addr, uint64_t dst_addr, uint32_t task_id) {
    // Different chip (high 32 bits) → remote
    if ((uint32_t)(src_addr >> 32) != (uint32_t)(dst_addr >> 32)) {
        xdma_remote_wait(task_id);
        return;
    }
    uint32_t src_lo = (uint32_t)src_addr;
    uint32_t dst_lo = (uint32_t)dst_addr;
    // Both in TCDM range and same cluster → local
    if (src_lo >= SNRT_TCDM_START_ADDR && dst_lo >= SNRT_TCDM_START_ADDR) {
        uint32_t src_cluster = (src_lo - SNRT_TCDM_START_ADDR) >> CLUSTER_ADDRWIDTH;
        uint32_t dst_cluster = (dst_lo - SNRT_TCDM_START_ADDR) >> CLUSTER_ADDRWIDTH;
        if (src_cluster == dst_cluster) {
            xdma_local_wait(task_id);
            return;
        }
    }
    xdma_remote_wait(task_id);
}

// Disable all xDMA datapath extensions (reader + writer).
// Must be called before any xDMA transfer to ensure clean state.
__attribute__((always_inline)) inline void xdma_disable_all_extensions() {
    for (uint8_t i = 0; i < XDMA_SRC_EXT_NUM; i++) {
        xdma_disable_src_ext(i);
    }
    for (uint8_t i = 0; i < XDMA_DST_EXT_NUM; i++) {
        xdma_disable_dst_ext(i);
    }
}

inline uint32_t xdma_last_task_cycle() {
    return snax_read_xdma_cfg_reg(XDMA_PERF_CTR_TASK);
}

inline uint32_t xdma_last_read_cycle() {
    return snax_read_xdma_cfg_reg(XDMA_PERF_CTR_READER);
}

inline uint32_t xdma_last_write_cycle() {
    return snax_read_xdma_cfg_reg(XDMA_PERF_CTR_WRITER);
}

// ============================================================================
// Layout-convert staging helper
// ============================================================================
// xDMA's reader is tied to the calling cluster's L1 TCDM, so the src of a
// layout-convert transfer must live in local L1. The writer, on the other
// hand, can target any address in the global space — so dst can be L3 or a
// remote cluster's L1 directly (no stage-out needed; xDMA performs the layout
// transform during the write).
//
// This helper:
//   1. If `src` already points inside the calling cluster's local L1, uses it
//      as-is (zero-copy fast path).
//   2. Otherwise allocates an L1 scratch buffer, IDMA-copies `bytes` of src
//      data into it, and returns the staged L1 address as `xdma_src`. The
//      caller should free it via `xdma_layout_stage_free` after xDMA finishes.
//
// Depends on runtime symbols that must already be visible at the include
// site: snrt_l1_start_addr / snrt_l1_end_addr (occamy_memory.h),
// snrt_l1_malloc / snrt_l1_free (snrt_l1_alloc.h), chiplet_addr_transform
// (chip_id.h), snrt_dma_start_1d_wideptr / snrt_dma_wait_all (snitch DMA).
typedef struct {
    uint64_t xdma_src;       // src address to pass to xDMA (always local L1)
    uint32_t stage_in_lo;    // L1 scratch ptr to free, or 0 for fast path
} xdma_layout_stage_t;

static inline int xdma_layout_stage_in(
    xdma_layout_stage_t *s, uint64_t src, uint32_t bytes)
{
    bool src_local = xdma_addr_in_local_l1(src);

    s->stage_in_lo = 0;
    if (src_local) {
        s->xdma_src = src;
        return 0;
    }
    s->stage_in_lo = snrt_l1_malloc(bytes);
    if (!s->stage_in_lo) {
        return -1;
    }
    snrt_dma_start_1d_wideptr(
        chiplet_addr_transform((uint64_t)s->stage_in_lo),
        src, bytes);
    snrt_dma_wait_all();
    s->xdma_src = chiplet_addr_transform((uint64_t)s->stage_in_lo);
    return 0;
}

static inline void xdma_layout_stage_free(xdma_layout_stage_t *s) {
    if (s->stage_in_lo) {
        snrt_l1_free(s->stage_in_lo);
        s->stage_in_lo = 0;
    }
}
